App({
  globalData: { userInfo: null, userId: null, partnerId: null },

  onLaunch() {
    let userId = wx.getStorageSync('userId');
    if (!userId) {
      userId = 'u_' + Date.now() + '_' + Math.random().toString(36).substr(2,8);
      wx.setStorageSync('userId', userId);
    }
    this.globalData.userId = userId;
    this.globalData.userInfo = wx.getStorageSync('userInfo') || { name: '我', avatar: '🌟' };
    this._initDefaultHabits();
  },

  _initDefaultHabits() {
    if (!wx.getStorageSync('habits') || !wx.getStorageSync('habits').length) {
      wx.setStorageSync('habits', [
        { id: 'h1', name: '早起', icon: '🌅', color: '#FF9500', target: 1,  unit: '次',  category: 'lifestyle' },
        { id: 'h2', name: '运动', icon: '🏃', color: '#FF375F', target: 30, unit: '分钟', category: 'health' },
        { id: 'h3', name: '读书', icon: '📚', color: '#007AFF', target: 20, unit: '页',  category: 'learning' },
        { id: 'h4', name: '喝水', icon: '💧', color: '#32ADE6', target: 8,  unit: '杯',  category: 'health' },
        { id: 'h5', name: '冥想', icon: '🧘', color: '#BF5AF2', target: 10, unit: '分钟', category: 'mind' },
        { id: 'h6', name: '早睡', icon: '🌙', color: '#5856D6', target: 1,  unit: '次',  category: 'lifestyle' },
      ]);
    }
  },

  getToday() {
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
  }
});

