// pages/index/index.js
const DB = require('../../utils/db');

Page({
  data: {
    userInfo: { name: '我', avatar: '🌟' },
    habits: [],
    todayRecords: {},
    habitStreaks: {},
    habitPct: {},
    completedCount: 0,
    totalHabits: 0,
    todayRate: 0,
    totalStreak: 0,
    isAllDone: false,
    ringColor: '#007AFF',
    headerDate: '',
    weekDays: [],
    partnerInfo: null,
    partnerCompleted: 0,
    partnerTotal: 0,
    partnerRate: 0,

    showCheckSheet: false,
    currentHabit: {},
    currentValue: 1,
    quickVals: [1, 5, 10, 20],

    showAddSheet: false,
    newHabit: { name: '', icon: '⭐', color: '#007AFF', target: 1, unit: '次' },
    emojiList: ['⭐','🌟','💪','🏃','📚','💧','🧘','🌅','🌙','🎯','✍️','🥗','🎵','☕','🚴','🏊','🍎','🛏️','🧹','💊'],
    colorList: ['#007AFF','#34C759','#FF9500','#FF375F','#BF5AF2','#5856D6','#32ADE6','#00C7BE','#FF3B30','#FFCC00'],
  },

  onLoad() {
    this.buildHeader();
    this.buildWeek();
    this.load();
  },
  onShow() { this.load(); },

  buildHeader() {
    const d = new Date();
    const months = ['一月','二月','三月','四月','五月','六月','七月','八月','九月','十月','十一月','十二月'];
    const days = ['星期日','星期一','星期二','星期三','星期四','星期五','星期六'];
    this.setData({ headerDate: `${months[d.getMonth()]} · ${days[d.getDay()]}` });
  },

  buildWeek() {
    const all = wx.getStorageSync('checkRecords') || {};
    const habits = DB.getHabits();
    const today = DB.getToday();
    const labels = ['日','一','二','三','四','五','六'];
    const days = [];
    for (let i = -3; i <= 3; i++) {
      const d = new Date(); d.setDate(d.getDate() + i);
      const s = `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
      const r = all[s] || {};
      let done = 0; habits.forEach(h => { if (r[h.id] && r[h.id].completed) done++; });
      days.push({ date: s, wl: labels[d.getDay()], d: d.getDate(), isToday: s === today, hasRecord: done > 0, isComplete: done === habits.length && habits.length > 0, isPartial: done > 0 && done < habits.length, isFuture: i > 0 });
    }
    this.setData({ weekDays: days });
  },

  load() {
    const habits = DB.getHabits();
    const records = DB.getTodayRecords();
    const partner = DB.getPartnerInfo();
    const userInfo = wx.getStorageSync('userInfo') || { name: '我', avatar: '🌟' };
    const streaks = {}, pct = {};
    let done = 0;
    habits.forEach(h => {
      streaks[h.id] = DB.getHabitStreak(h.id);
      const v = records[h.id] ? records[h.id].value : 0;
      pct[h.id] = Math.min(Math.round(v / h.target * 100), 100);
      if (records[h.id] && records[h.id].completed) done++;
    });
    const total = habits.length;
    const rate = total > 0 ? Math.round(done / total * 100) : 0;
    const streak = DB.getTotalStreak();
    const allDone = total > 0 && done === total;
    const ringColor = allDone ? '#34C759' : rate > 60 ? '#FF9500' : '#007AFF';

    let pc = 0, pt = 0, pr = 0;
    if (partner) {
      const pr2 = DB.getPartnerTodayRecords();
      habits.forEach(h => { if (pr2[h.id] && pr2[h.id].completed) pc++; });
      pt = habits.length; pr = pt > 0 ? Math.round(pc / pt * 100) : 0;
    }

    this.setData({ habits, todayRecords: records, habitStreaks: streaks, habitPct: pct, completedCount: done, totalHabits: total, todayRate: rate, totalStreak: streak, isAllDone: allDone, ringColor, userInfo, partnerInfo: partner, partnerCompleted: pc, partnerTotal: pt, partnerRate: pr });
    this.buildWeek();
  },

  tapHabit(e) {
    const h = e.currentTarget.dataset.habit;
    const r = this.data.todayRecords[h.id];
    const cv = r ? r.value : h.target;
    const q = [...new Set([1, Math.ceil(h.target*0.25), Math.ceil(h.target*0.5), h.target].map(x => Math.max(1,x)))].sort((a,b)=>a-b);
    this.setData({ showCheckSheet: true, currentHabit: h, currentValue: cv, quickVals: q });
  },
  stepUp()   { this.setData({ currentValue: this.data.currentValue + 1 }); },
  stepDown() { this.setData({ currentValue: Math.max(0, this.data.currentValue - 1) }); },
  setQuick(e){ this.setData({ currentValue: e.currentTarget.dataset.val }); },
  closeCheckSheet() { this.setData({ showCheckSheet: false }); },

  confirmCheck() {
    const { currentHabit, currentValue } = this.data;
    if (currentValue <= 0) { wx.showToast({ title: '请输入数量', icon: 'none' }); return; }
    DB.checkIn(currentHabit.id, currentValue);
    DB.updateChallengeProgress();
    this.setData({ showCheckSheet: false });
    this.load();
    const done = currentValue >= currentHabit.target;
    wx.showToast({ title: done ? '打卡成功 ✓' : '已记录', icon: 'none', duration: 1200 });
  },

  undoCheck() {
    wx.showModal({ title: '撤销打卡', content: `撤销"${this.data.currentHabit.name}"今日打卡？`,
      success: r => { if (r.confirm) { DB.undoCheckIn(this.data.currentHabit.id); this.setData({ showCheckSheet: false }); this.load(); }}
    });
  },

  openAddHabit() { this.setData({ showAddSheet: true, newHabit: { name:'', icon:'⭐', color:'#007AFF', target:1, unit:'次' } }); },
  closeAddSheet() { this.setData({ showAddSheet: false }); },
  pickEmoji(e)  { this.setData({ 'newHabit.icon': e.currentTarget.dataset.e }); },
  pickColor(e)  { this.setData({ 'newHabit.color': e.currentTarget.dataset.c }); },
  onNameInput(e){ this.setData({ 'newHabit.name': e.detail.value }); },
  onTargetInput(e){ this.setData({ 'newHabit.target': parseInt(e.detail.value)||1 }); },
  onUnitInput(e){ this.setData({ 'newHabit.unit': e.detail.value }); },

  saveHabit() {
    if (!this.data.newHabit.name.trim()) { wx.showToast({ title: '请输入名称', icon: 'none' }); return; }
    DB.addHabit(this.data.newHabit);
    this.setData({ showAddSheet: false });
    this.load();
    wx.showToast({ title: '习惯已添加', icon: 'none' });
  },

  tapDay() {},
  showProfile() {
    wx.showModal({ title: '我的配对码', content: DB.getMyCoupleCode(), showCancel: false });
  },
  goPartner() { wx.switchTab({ url: '/pages/partner/partner' }); },
});

