     1→// utils/db.js
     2→const DB = {
     3→  getToday() {
     4→    const d = new Date();
     5→    return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
     6→  },
     7→  getCurrentTime() {
     8→    const d = new Date();
     9→    return `${String(d.getHours()).padStart(2,'0')}:${String(d.getMinutes()).padStart(2,'0')}`;
    10→  },
    11→  getHabits() { return wx.getStorageSync('habits') || []; },
    12→  saveHabits(h) { wx.setStorageSync('habits', h); },
    13→  addHabit(h) {
    14→    const list = this.getHabits();
    15→    const n = { id:'h_'+Date.now(), name:h.name, icon:h.icon||'⭐', color:h.color||'#007AFF', target:h.target||1, unit:h.unit||'次', category:h.category||'custom' };
    16→    list.push(n); this.saveHabits(list); return n;
    17→  },
    18→  deleteHabit(id) { this.saveHabits(this.getHabits().filter(h=>h.id!==id)); },
    19→  getAllRecords() { return wx.getStorageSync('checkRecords') || {}; },
    20→  getDateRecords(date) { return (this.getAllRecords()[date]) || {}; },
    21→  getTodayRecords() { return this.getDateRecords(this.getToday()); },
    22→  checkIn(habitId, value) {
    23→    const today = this.getToday();
    24→    const all = this.getAllRecords();
    25→    if (!all[today]) all[today] = {};
    26→    const target = this.getHabitTarget(habitId);
    27→    all[today][habitId] = { value, time: this.getCurrentTime(), timestamp: Date.now(), completed: value >= target };
    28→    wx.setStorageSync('checkRecords', all);
    29→    return all[today];
    30→  },
    31→  undoCheckIn(id) {
    32→    const today = this.getToday();
    33→    const all = this.getAllRecords();
    34→    if (all[today]) { delete all[today][id]; wx.setStorageSync('checkRecords', all); }
    35→  },
    36→  getHabitTarget(id) { const h = this.getHabits().find(x=>x.id===id); return h?h.target:1; },
    37→  getHabitStreak(id) {
    38→    const all = this.getAllRecords(); const target = this.getHabitTarget(id);
    39→    let streak=0; const d=new Date();
    40→    for(let i=0;i<365;i++){
    41→      const s=`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
    42→      const r=all[s]; if(r&&r[id]&&r[id].value>=target){streak++;d.setDate(d.getDate()-1);}else break;
    43→    }
    44→    return streak;
    45→  },
    46→  getTotalStreak() {
    47→    const h=this.getHabits(); const all=this.getAllRecords();
    48→    if(!h.length) return 0;
    49→    let streak=0; const d=new Date();
    50→    for(let i=0;i<365;i++){
    51→      const s=`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
    52→      const r=all[s]||{}; const done=h.every(x=>r[x.id]&&r[x.id].completed);
    53→      if(done){streak++;d.setDate(d.getDate()-1);}else break;
    54→    }
    55→    return streak;
    56→  },
    57→  getMonthStats(year,month) {
    58→    const all=this.getAllRecords(); const habits=this.getHabits();
    59→    const days=new Date(year,month,0).getDate(); const today=this.getToday();
    60→    let completeDays=0; const cal=[];
