// utils/db.js
const DB = {
  getToday() {
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
  },
  getCurrentTime() {
    const d = new Date();
    return `${String(d.getHours()).padStart(2,'0')}:${String(d.getMinutes()).padStart(2,'0')}`;
  },
  getHabits() { return wx.getStorageSync('habits') || []; },
  saveHabits(h) { wx.setStorageSync('habits', h); },
  addHabit(h) {
    const list = this.getHabits();
    const n = { id:'h_'+Date.now(), name:h.name, icon:h.icon||'⭐', color:h.color||'#007AFF', target:h.target||1, unit:h.unit||'次', category:h.category||'custom' };
    list.push(n); this.saveHabits(list); return n;
  },
  deleteHabit(id) { this.saveHabits(this.getHabits().filter(h=>h.id!==id)); },
  getAllRecords() { return wx.getStorageSync('checkRecords') || {}; },
  getDateRecords(date) { return (this.getAllRecords()[date]) || {}; },
  getTodayRecords() { return this.getDateRecords(this.getToday()); },
  checkIn(habitId, value) {
    const today = this.getToday();
    const all = this.getAllRecords();
    if (!all[today]) all[today] = {};
    const target = this.getHabitTarget(habitId);
    all[today][habitId] = { value, time: this.getCurrentTime(), timestamp: Date.now(), completed: value >= target };
    wx.setStorageSync('checkRecords', all);
    return all[today];
  },
  undoCheckIn(id) {
    const today = this.getToday();
    const all = this.getAllRecords();
    if (all[today]) { delete all[today][id]; wx.setStorageSync('checkRecords', all); }
  },
  getHabitTarget(id) { const h = this.getHabits().find(x=>x.id===id); return h?h.target:1; },
  getHabitStreak(id) {
    const all = this.getAllRecords(); const target = this.getHabitTarget(id);
    let streak=0; const d=new Date();
    for(let i=0;i<365;i++){
      const s=`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
      const r=all[s]; if(r&&r[id]&&r[id].value>=target){streak++;d.setDate(d.getDate()-1);}else break;
    }
    return streak;
  },
  getTotalStreak() {
    const h=this.getHabits(); const all=this.getAllRecords();
    if(!h.length) return 0;
    let streak=0; const d=new Date();
    for(let i=0;i<365;i++){
      const s=`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
      const r=all[s]||{}; const done=h.every(x=>r[x.id]&&r[x.id].completed);
      if(done){streak++;d.setDate(d.getDate()-1);}else break;
    }
    return streak;
  },
  getMonthStats(year,month) {
    const all=this.getAllRecords(); const habits=this.getHabits();
    const days=new Date(year,month,0).getDate(); const today=this.getToday();
    let completeDays=0; const cal=[];
    for(let day=1;day<=days;day++){
      const ds=`${year}-${String(month).padStart(2,'0')}-${String(day).padStart(2,'0')}`;
      const r=all[ds]||{}; let done=0;
      habits.forEach(h=>{if(r[h.id]&&r[h.id].completed)done++;});
      const isToday=ds===today; const isFuture=new Date(ds)>new Date()&&!isToday;
      const isComplete=done===habits.length&&habits.length>0;
      const isPartial=done>0&&done<habits.length;
      if(isComplete&&!isFuture)completeDays++;
      cal.push({day,date:ds,done,total:habits.length,isComplete,isPartial,isToday,isFuture});
    }
    const now=new Date(); const passed=year===now.getFullYear()&&month===now.getMonth()+1?now.getDate():days;
    return { completeDays, missedDays:passed-completeDays, checkRate:passed>0?Math.round(completeDays/passed*100):0, calendarData:cal };
  },
  getRecentHistory(limit=15) {
    const all=this.getAllRecords(); const habits=this.getHabits();
    return Object.keys(all).sort().reverse().slice(0,limit).map(date=>{
      const r=all[date]; const done=habits.filter(h=>r[h.id]&&r[h.id].completed);
      const today=this.getToday(); const yd=(()=>{const d=new Date();d.setDate(d.getDate()-1);return`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;})();
      const disp=date===today?'今天':date===yd?'昨天':`${date.split('-')[1]}月${date.split('-')[2]}日`;
      return {date,displayDate:disp,done,total:habits.length,rate:habits.length?Math.round(done.length/habits.length*100):0};
    }).filter(x=>x.done.length>0);
  },
  getMyCoupleCode() {
    let c=wx.getStorageSync('myCoupleCode');
    if(!c){c='ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789'.split('').sort(()=>Math.random()-.5).slice(0,6).join('');wx.setStorageSync('myCoupleCode',c);}
    return c;
  },
  getPartnerInfo() { return wx.getStorageSync('partnerInfo')||null; },
  bindPartner(code) {
    const p={id:'p_'+code,name:'我的搭档',avatar:'',coupleCode:code,bindTime:new Date().toISOString()};
    wx.setStorageSync('partnerInfo',p); return p;
  },
  getPartnerTodayRecords() { return wx.getStorageSync('partnerTodayRecords')||{}; },
  getReactions() { return wx.getStorageSync('reactions')||[]; },
  sendReaction(emoji) {
    const r=this.getReactions();
    r.push({id:Date.now(),emoji,fromMe:true,time:this.getCurrentTime(),date:this.getToday()});
    if(r.length>50)r.splice(0,r.length-50);
    wx.setStorageSync('reactions',r);
  },
  getChallenges() { return wx.getStorageSync('challenges')||[]; },
  createChallenge(c) {
    const list=this.getChallenges();
    const n={id:'c_'+Date.now(),title:c.title,habitId:c.habitId,targetDays:c.targetDays||7,startDate:this.getToday(),status:'active',myProgress:0,partnerProgress:0};
    list.push(n); wx.setStorageSync('challenges',list); return n;
  },
  updateChallengeProgress() {
    const list=this.getChallenges(); const today=this.getToday(); const r=this.getTodayRecords();
    list.forEach(c=>{
      if(c.status==='active'){
        if(r[c.habitId]&&r[c.habitId].completed&&c.lastCountDate!==today){c.myProgress=(c.myProgress||0)+1;c.lastCountDate=today;}
        if(c.myProgress>=c.targetDays)c.status='myComplete';
      }
    });
    wx.setStorageSync('challenges',list); return list;
  }
};
module.exports = DB;

