// pages/statistics/statistics.js
const DB = require('../../utils/db');
Page({
  data: {
    headerDate:'', totalStreak:0, monthStats:{completeDays:0,checkRate:0},
    currentYear:0, currentMonth:0, isCurrentMonth:true,
    wls:['日','一','二','三','四','五','六'], emptyDays:[], calData:[],
    habitStats:[], history:[],
  },
  onLoad() {
    const d=new Date();
    const months=['一月','二月','三月','四月','五月','六月','七月','八月','九月','十月','十一月','十二月'];
    const days=['星期日','星期一','星期二','星期三','星期四','星期五','星期六'];
    this.setData({ headerDate:`${months[d.getMonth()]} · ${days[d.getDay()]}`, currentYear:d.getFullYear(), currentMonth:d.getMonth()+1, isCurrentMonth:true });
    this.load();
  },
  onShow() { this.load(); },
  load() {
    const {currentYear:y,currentMonth:m}=this.data;
    const habits=DB.getHabits(); const all=wx.getStorageSync('checkRecords')||{};
    const ms=DB.getMonthStats(y,m); const history=DB.getRecentHistory(12);
    const firstDay=new Date(y,m-1,1).getDay();
    const emptyDays=Array(firstDay).fill(0);
    const now=new Date();
    const isCurrentMonth=y===now.getFullYear()&&m===now.getMonth()+1;
    const habitStats=habits.map(h=>{
      const streak=DB.getHabitStreak(h.id);
      let md=0,td=0;
      Object.keys(all).forEach(date=>{
        const r=all[date]; if(r[h.id]&&r[h.id].completed){td++;if(date.startsWith(`${y}-${String(m).padStart(2,'0')}`))md++;}
      });
      const passed=isCurrentMonth?now.getDate():new Date(y,m,0).getDate();
      const monthRate=passed>0?Math.round(md/passed*100):0;
      return{...h,streak,monthDays:md,totalDays:td,monthRate};
    });
    this.setData({totalStreak:DB.getTotalStreak(),monthStats:ms,calData:ms.calendarData,emptyDays,habitStats,history,isCurrentMonth});
  },
  prevMonth(){let{currentYear:y,currentMonth:m}=this.data;m--;if(m<1){m=12;y--;}this.setData({currentYear:y,currentMonth:m});this.load();},
  nextMonth(){if(this.data.isCurrentMonth)return;let{currentYear:y,currentMonth:m}=this.data;m++;if(m>12){m=1;y++;}this.setData({currentYear:y,currentMonth:m});this.load();}
});

