// pages/challenge/challenge.js
const DB = require('../../utils/db');
Page({
  data: {
    headerDate: '',
    challenges: [], activeCnt: 0, doneCnt: 0,
    habits: [],
    showCreate: false,
    nc: { title: '', habitId: '', targetDays: 7 },
    dayOptions: [7, 14, 21, 30],
    templates: [
      { id:'t1', emoji:'🏃', title:'7天运动',    days:7,  bg:'#FFF3E8' },
      { id:'t2', emoji:'📚', title:'21天阅读',   days:21, bg:'#EEF3FF' },
      { id:'t3', emoji:'💧', title:'14天喝水',   days:14, bg:'#E8F9FF' },
      { id:'t4', emoji:'🌅', title:'30天早起',   days:30, bg:'#FFFBEA' },
      { id:'t5', emoji:'🧘', title:'10天冥想',   days:10, bg:'#F4EEFF' },
    ],
  },
  onLoad() {
    const d = new Date();
    const months = ['一月','二月','三月','四月','五月','六月','七月','八月','九月','十月','十一月','十二月'];
    const days = ['星期日','星期一','星期二','星期三','星期四','星期五','星期六'];
    this.setData({ headerDate: `${months[d.getMonth()]} · ${days[d.getDay()]}` });
    this.load();
  },
  onShow() { this.load(); },
  load() {
    const habits = DB.getHabits();
    const raw = DB.updateChallengeProgress();
    const today = DB.getToday();
    const challenges = raw.map(c => {
      const h = habits.find(x => x.id === c.habitId);
      const end = new Date(c.startDate); end.setDate(end.getDate() + c.targetDays);
      const daysLeft = Math.max(0, Math.ceil((end - new Date()) / 86400000));
      const parts = c.startDate.split('-');
      return {
        ...c,
        habitName: h ? h.name : '',
        habitIcon: h ? h.icon : '⭐',
        myRate:      Math.min(Math.round((c.myProgress      / c.targetDays) * 100), 100),
        partnerRate: Math.min(Math.round((c.partnerProgress / c.targetDays) * 100), 100),
        daysLeft,
        displayStart: `${parts[1]}月${parts[2]}日`,
      };
    });
    this.setData({
      challenges,
      habits,
      activeCnt: challenges.filter(c => c.status === 'active').length,
      doneCnt:   challenges.filter(c => c.status === 'myComplete').length,
    });
  },
  openCreate() {
    if (!DB.getPartnerInfo()) {
      wx.showModal({ title: '需要绑定搭档', content: '先绑定搭档再发起双人挑战吧', confirmText: '去绑定',
        success: r => { if (r.confirm) wx.switchTab({ url: '/pages/partner/partner' }); }
      });
      return;
    }
    const habits = DB.getHabits();
    this.setData({ showCreate: true, nc: { title: '', habitId: habits[0] ? habits[0].id : '', targetDays: 7 } });
  },
  closeCreate() { this.setData({ showCreate: false }); },
  onTitleInput(e) { this.setData({ 'nc.title': e.detail.value }); },
  selectHabit(e) { this.setData({ 'nc.habitId': e.currentTarget.dataset.h.id }); },
  selectDays(e)  { this.setData({ 'nc.targetDays': e.currentTarget.dataset.d }); },
  createChallenge() {
    const { nc } = this.data;
    if (!nc.title.trim()) { wx.showToast({ title: '请输入挑战名称', icon: 'none' }); return; }
    if (!nc.habitId)       { wx.showToast({ title: '请选择习惯',     icon: 'none' }); return; }
    DB.createChallenge(nc);
    this.setData({ showCreate: false });
    this.load();
    wx.showToast({ title: '挑战已发起 ⚡', icon: 'none', duration: 1500 });
  },
  useTemplate(e) {
    const t = e.currentTarget.dataset.t;
    const habits = DB.getHabits();
    this.setData({ showCreate: true, nc: { title: t.title, habitId: habits[0] ? habits[0].id : '', targetDays: t.days } });
  },
});

