/* app.wxss — Apple iOS 18 / visionOS Design System */

page {
  /* ── System Backgrounds ── */
  --bg:            #F2F2F7;
  --bg-elevated:   #FFFFFF;
  --bg-grouped:    #F2F2F7;

  /* ── Fill Materials ── */
  --fill-1: rgba(120,120,128,0.20);
  --fill-2: rgba(120,120,128,0.16);
  --fill-3: rgba(118,118,128,0.12);
  --fill-4: rgba(116,116,128,0.08);

  /* ── Labels ── */
  --label:   #000000;
  --label-2: rgba(60,60,67,0.60);
  --label-3: rgba(60,60,67,0.30);
  --label-4: rgba(60,60,67,0.18);

  /* ── Separators ── */
  --sep:        rgba(60,60,67,0.29);
  --sep-light:  rgba(60,60,67,0.10);

  /* ── iOS System Colors ── */
  --blue:    #007AFF;
  --green:   #34C759;
  --indigo:  #5856D6;
  --orange:  #FF9500;
  --pink:    #FF375F;
  --purple:  #BF5AF2;
  --red:     #FF3B30;
  --teal:    #32ADE6;
  --yellow:  #FFCC00;
  --mint:    #00C7BE;
  --cyan:    #32ADE6;

  /* ── Tinted Surfaces ── */
  --blue-tint:   rgba(0,122,255,0.10);
  --green-tint:  rgba(52,199,89,0.10);
  --orange-tint: rgba(255,149,0,0.10);
  --pink-tint:   rgba(255,55,95,0.10);
  --purple-tint: rgba(191,90,242,0.10);
  --red-tint:    rgba(255,59,48,0.08);
  --teal-tint:   rgba(50,174,230,0.10);
  --mint-tint:   rgba(0,199,190,0.10);

  /* ── Shadows ── */
  --shadow-xs: 0 1rpx 4rpx rgba(0,0,0,0.05);
  --shadow-sm: 0 2rpx 16rpx rgba(0,0,0,0.07), 0 0 1rpx rgba(0,0,0,0.03);
  --shadow-md: 0 8rpx 40rpx rgba(0,0,0,0.10), 0 2rpx 8rpx rgba(0,0,0,0.05);
  --shadow-lg: 0 20rpx 60rpx rgba(0,0,0,0.16), 0 4rpx 20rpx rgba(0,0,0,0.08);

  /* ── Radii ── */
  --r-xs:   8rpx;
  --r-sm:   12rpx;
  --r-md:   16rpx;
  --r-lg:   22rpx;
  --r-xl:   28rpx;
  --r-2xl:  36rpx;
  --r-3xl:  48rpx;
  --r-full: 9999rpx;

  /* ── Type scale (SF Pro) ── */
  --f-largetitle: 68rpx;
  --f-title1:     52rpx;
  --f-title2:     44rpx;
  --f-title3:     36rpx;
  --f-headline:   34rpx;
  --f-body:       34rpx;
  --f-callout:    32rpx;
  --f-subhead:    30rpx;
  --f-footnote:   26rpx;
  --f-caption1:   24rpx;
  --f-caption2:   22rpx;

  font-family: -apple-system, 'SF Pro Display', 'PingFang SC', 'Helvetica Neue', sans-serif;
  font-size: var(--f-body);
  line-height: 1.5;
  color: var(--label);
  background: var(--bg);
}

view, text, button, input, image { box-sizing: border-box; }
button { border: none; padding: 0; margin: 0; background: transparent; }
button::after { border: none; }

/* ── Page ── */
.page { min-height: 100vh; background: var(--bg); padding-bottom: 180rpx; }

/* ── Sections ── */
.section { margin: 0 32rpx 8rpx; }
.section-hd {
  padding: 28rpx 4rpx 12rpx;
  display: flex;
  align-items: baseline;
  justify-content: space-between;
}
.section-title {
  font-size: var(--f-footnote);
  font-weight: 600;
  color: var(--label-2);
  text-transform: uppercase;
  letter-spacing: 1rpx;
}
.section-more { font-size: var(--f-subhead); color: var(--blue); font-weight: 500; }

/* ── Cards ── */
.card {
  background: var(--bg-elevated);
  border-radius: var(--r-xl);
  box-shadow: var(--shadow-sm);
  overflow: hidden;
}
.card-p32 {
  background: var(--bg-elevated);
  border-radius: var(--r-xl);
  box-shadow: var(--shadow-sm);
  padding: 32rpx;
}

/* ── List rows inside card ── */
.row {
  display: flex;
  align-items: center;
  padding: 22rpx 24rpx;
  background: var(--bg-elevated);
  position: relative;
  gap: 16rpx;
}
.row + .row::before {
  content: '';
  position: absolute;
  top: 0; left: 76rpx; right: 0;
  height: 1rpx;
  background: var(--sep-light);
}

/* ── Typography ── */
.f-largetitle { font-size: var(--f-largetitle); font-weight: 800; letter-spacing: -2rpx; line-height: 1.05; }
.f-title1     { font-size: var(--f-title1);     font-weight: 700; letter-spacing: -1.5rpx; line-height: 1.1; }
.f-title2     { font-size: var(--f-title2);     font-weight: 700; letter-spacing: -1rpx; }
.f-title3     { font-size: var(--f-title3);     font-weight: 600; }
.f-headline   { font-size: var(--f-headline);   font-weight: 600; }
.f-body       { font-size: var(--f-body);       font-weight: 400; }
.f-callout    { font-size: var(--f-callout);    font-weight: 400; }
.f-subhead    { font-size: var(--f-subhead);    font-weight: 400; }
.f-footnote   { font-size: var(--f-footnote);   font-weight: 400; }
.f-caption1   { font-size: var(--f-caption1);   font-weight: 400; }
.f-caption2   { font-size: var(--f-caption2);   font-weight: 400; }

/* ── Buttons ── */
.btn-primary {
  display: flex; align-items: center; justify-content: center;
  background: var(--blue); color: #fff;
  border-radius: var(--r-full);
  font-size: var(--f-headline); font-weight: 600;
  height: 100rpx;
}
.btn-tinted {
  display: flex; align-items: center; justify-content: center;
  background: var(--blue-tint); color: var(--blue);
  border-radius: var(--r-full);
  font-size: var(--f-callout); font-weight: 600;
  height: 88rpx; padding: 0 40rpx;
}
.btn-gray {
  display: flex; align-items: center; justify-content: center;
  background: var(--fill-3); color: var(--label);
  border-radius: var(--r-full);
  font-size: var(--f-callout); font-weight: 500;
  height: 88rpx; padding: 0 40rpx;
}
.btn-destructive {
  display: flex; align-items: center; justify-content: center;
  background: var(--red-tint); color: var(--red);
  border-radius: var(--r-full);
  font-size: var(--f-callout); font-weight: 600;
  height: 88rpx; padding: 0 40rpx;
}

/* ── Chips ── */
.chip {
  display: inline-flex; align-items: center; gap: 4rpx;
  padding: 6rpx 16rpx;
  border-radius: var(--r-full);
  font-size: var(--f-caption1); font-weight: 600;
}
.chip-blue   { background: var(--blue-tint);   color: var(--blue); }
.chip-green  { background: var(--green-tint);  color: var(--green); }
.chip-orange { background: var(--orange-tint); color: var(--orange); }
.chip-pink   { background: var(--pink-tint);   color: var(--pink); }
.chip-purple { background: var(--purple-tint); color: var(--purple); }
.chip-teal   { background: var(--teal-tint);   color: var(--teal); }

/* ── Progress ── */
.prog-track {
  background: var(--fill-3);
  border-radius: var(--r-full);
  overflow: hidden;
}
.prog-fill {
  height: 100%;
  border-radius: var(--r-full);
  transition: width 0.7s cubic-bezier(0.34,1.2,0.64,1);
}

/* ── Sheet (bottom drawer) ── */
.overlay {
  position: fixed; top: 0; left: 0; right: 0; bottom: 0;
  background: rgba(0,0,0,0);
  z-index: 300;
  display: flex; align-items: flex-end;
  pointer-events: none;
  transition: background 0.28s ease;
}
.overlay.show {
  background: rgba(0,0,0,0.36);
  pointer-events: all;
}
.sheet {
  width: 100%;
  background: var(--bg-elevated);
  border-radius: var(--r-3xl) var(--r-3xl) 0 0;
  padding-bottom: 40rpx;
  transform: translateY(100%);
  transition: transform 0.38s cubic-bezier(0.32,0.72,0,1);
  box-shadow: var(--shadow-lg);
}
.overlay.show .sheet { transform: translateY(0); }
.grabber {
  width: 72rpx; height: 8rpx;
  background: var(--fill-2);
  border-radius: var(--r-full);
  margin: 16rpx auto 0;
}
.sheet-body { padding: 16rpx 32rpx 40rpx; }

/* ── Animations ── */
@keyframes fadeUp {
  from { opacity: 0; transform: translateY(20rpx); }
  to   { opacity: 1; transform: translateY(0); }
}
@keyframes scaleIn {
  0%   { transform: scale(0.7); opacity: 0; }
  60%  { transform: scale(1.08); }
  100% { transform: scale(1); opacity: 1; }
}
@keyframes checkBounce {
  0%   { transform: scale(0) rotate(-10deg); }
  55%  { transform: scale(1.25) rotate(3deg); }
  100% { transform: scale(1) rotate(0); }
}
.anim-up    { animation: fadeUp 0.4s ease both; }
.anim-scale { animation: scaleIn 0.45s cubic-bezier(0.34,1.56,0.64,1) both; }
.anim-check { animation: checkBounce 0.42s cubic-bezier(0.34,1.56,0.64,1) both; }

